public static void main(Args _args)
{
    ETGVendAgingMMRController controller = new ETGVendAgingMMRController();


    if (curExt() == "o025")
    {
        controller.parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign3));
    }
    else
    {
        controller.parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign1));
    }

    controller.parmArgs(_args);
    controller.parmDialogCaption("Vendor Aging MMR");
    controller.startOperation();
}

protected void prePromptModifyContract()
{
    super();

    ETGVendAgingMMRContract contract = this.parmReportContract().parmRdpContract() as ETGVendAgingMMRContract;

    if (curExt() == "o025")
    {
        if (contract.parmReportType() == ETGReportType::Summary)
        {
            this.parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign4));
            this.parmReportContract().parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign4));
        }
        else
        {
            this.parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign3));
            this.parmReportContract().parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign3));
        }
    }
    else
    {
        if (contract.parmReportType() == ETGReportType::Summary)
        {
            this.parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign2));
            this.parmReportContract().parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign2));
        }
        else
        {
            this.parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign1));
            this.parmReportContract().parmReportName(ssrsReportStr(ETGVendAgingMMR, PrecisionDesign1));
        }
    }
}

